// // This module captures an input signal, `di`, on the falling edge of the clock unless the hold signal, `hld`, is deasserted.
module top_module(input clk, rst, input di, input hld, output reg q = 0);reg q1 = 0;

always @(posedge clk) begin
	if (rst) begin
		q <= 0;
    q1 <= 0;
	end else begin
    if (~hld) begin
      q <= q1;
      q1 <= di;
    end
  end
end

endmodule
